34	const calculateComponentPremium = (count: number): number =>
35	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
36	
37	const calculateMainItemPremium = (item: any): number => {
38	  const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
39	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
40	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
41	  return base + curseSurcharge + enchantmentSurcharge;
42	};
