65	  return items.reduce((sum: number, item: any) => {
66	    if (isComponent(item)) {
67	      return sum + COMPONENT_INSURANCE_VALUE;
68	    }
69	    return sum + (INSURANCE_VALUES[item.type] ?? 0);
70	  }, 0);
71	};
