79	export function processScenario(scenario: any): unknown {
80	  let quoteCount = 0;
81	  const policies: Record<number, { items: any[]; remainingCap: number }> = {};
82	
83	  const results = scenario.steps.map((step: any, index: number) => {
84	    if (step.op === "quote") {
85	      const isFollowUp = quoteCount > 0;
86	      quoteCount++;
87	      const insuranceSum = calculateInsuranceSum(step.items);
88	      policies[index] = { items: step.items, remainingCap: insuranceSum * 2 };
89	      return { premium: calculateQuotePremium(step.items, scenario.customer, isFollowUp) };
90	    }
91	    if (step.op === "claim") {
92	      const policy = policies[step.policy];
93	      const payout = calculateClaimPayout(step.incident.damages);
94	      policy.remainingCap -= payout;
95	      return { payout, remainingCap: policy.remainingCap };
96	    }
97	  });
98	  return { results };
99	}
